export function LanguageProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<Lang>(() => {
    const saved = localStorage.getItem("kitt_lang") as Lang | null;
    if (saved && VALID_LANGS.includes(saved)) return saved;
    const browser = navigator.language.toLowerCase();
    if (browser.startsWith("fr")) return "fr";
    if (browser.startsWith("es")) return "es";
    if (browser.startsWith("pt")) return "pt";
    if (browser.startsWith("de")) return "de";
    if (browser.startsWith("nl")) return "nl";
    if (browser.startsWith("zh")) return "zh";
    if (browser.startsWith("ja")) return "ja";
    if (browser.startsWith("ko")) return "ko";
    return "en";
  });

  const setLang = (l: Lang) => {
    setLangState(l);
    localStorage.setItem("kitt_lang", l);
  };

  const toggle = () => {
    const idx = VALID_LANGS.indexOf(lang);
    setLang(VALID_LANGS[(idx + 1) % VALID_LANGS.length]);
  };

  const t = (key: string): string =>
    translations[lang]?.[key] ?? translations["en"]?.[key] ?? translations["fr"]?.[key] ?? key;

  return (
    <LanguageContext.Provider value={{ lang, toggle, setLang, t }}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage() {
  const ctx = useContext(LanguageContext);
  if (!ctx) throw new Error("useLanguage must be used within LanguageProvider");
  return ctx;
}
